// Ezt appStyle state nélkül is hívhatjuk, mert localStorage-ból olvas
function gc(type) {
  let m = false;
  try { m = localStorage.getItem("app_card_style") === "modern"; } catch(e) {}
  const map = {
    card:   m ? "#1a2535"  : "#1e2a3a",
    input:  m ? "#111c2a"  : "#0f1f30",
    dark:   m ? "#0f1824"  : "#162030",
    border: m ? "#2a3a50"  : "#2d4057",
    deep:   m ? "#090f1a"  : "#001a33",
  };
  return map[type] || "#1e2a3a";
}

