function AvatarImg({ avatar, size=32, style={} }) {
if(!avatar) return <span style={{ fontSize: size*0.7+"px" }}>👤</span>;
if(avatar.startsWith("data:") || avatar.startsWith("http")) {
return <img src={avatar} alt="avatar" style={{ width:size, height:size, borderRadius:"50%", objectFit:"cover", flexShrink:0, ...style }} />;
}
return <span style={{ fontSize: size*0.7+"px", lineHeight:1, ...style }}>{avatar}</span>;
}
