useE(() => {
const today3 = new Date(); today3.setDate(today3.getDate()+3);
const soon = szamlak.filter(s => s.statusz==="fizetendo" && s.hatarido && s.hatarido <= today3.toISOString().slice(0,10) && s.hatarido >= todayStr);
const overdue = szamlak.filter(s => s.statusz==="fizetendo" && s.hatarido && s.hatarido < todayStr);
if(soon.length > 0 || overdue.length > 0) setHatarIdoAlert({ soon, overdue });
}, [szamlak.length]);


useE(() => {
if(szamlak.length === 0) return;
const checkAndSend = async () => {
const now = new Date();
const nowDate = now.toISOString().slice(0,10);
const hh = now.getHours().toString().padStart(2, "0");
const mm = now.getMinutes().toString().padStart(2, "0");
const nowTime = `${hh}:${mm}`;
const pendingEmails = szamlak.filter(s =>
s.ertesitoDatum === nowDate &&
s.ertesitoEmail &&
!s.emailKikuldve &&
s.statusz === "fizetendo" &&
(s.ertesitoIdo || "09:00") <= nowTime
);
if(pendingEmails.length === 0) return;
let anyChanged = false;
const updatedSzamlak = await Promise.all(szamlak.map(async s => {
if(!pendingEmails.find(p => p.id === s.id)) return s;
const kat = SZAMLA_KAT.find(k=>k.id===s.kategoria) || SZAMLA_KAT[5];
try {
await emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, {
to_email: s.ertesitoEmail,
to_name: s.ertesitoEmail,
event_title: `💳 Számla emlékeztető: ${s.nev}`,
event_date: s.hatarido || "–",
event_time: s.ertesitoIdo || "–",
event_location: kat.emoji + " " + kat.label,
event_description: `Összeg: ${s.osszeg > 0 ? s.osszeg.toLocaleString("hu-HU") + " Ft" : "–"}
Határidő: ${s.hatarido || "–"}

Ez egy automatikus emlékeztető a Családi Feladatkezelő alkalmazástól.`,
days_before: "💳 Számla emlékeztető!",
emoji: "💳",
});
console.log("📧 Számla email elküldve:", s.nev, "→", s.ertesitoEmail);
anyChanged = true;
return { ...s, emailKikuldve: nowDate };
} catch(e) {
console.warn("Számla email küldési hiba:", e);
return s;
}
}));
if(anyChanged) saveKoltsegData({ ...data, szamlak: updatedSzamlak });
};
checkAndSend();
const interval = setInterval(checkAndSend, 60000);
return () => clearInterval(interval);
}, [szamlak.length]);

const sendSzamlaEmail = async (szamla, auto = false) => {
if(!szamla.ertesitoEmail) return;
const sid = szamla.id;
setEmailKuldesAllapot(prev => ({...prev, [sid]: "sending"}));
const kat = SZAMLA_KAT.find(k=>k.id===szamla.kategoria) || SZAMLA_KAT[5];
try {
await emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, {
to_email: szamla.ertesitoEmail,
to_name: szamla.ertesitoEmail,
event_title: `💳 Számla emlékeztető: ${szamla.nev}`,
event_date: szamla.hatarido || "–",
event_time: "–",
event_location: kat.emoji + " " + kat.label,
event_description: `Összeg: ${szamla.osszeg > 0 ? szamla.osszeg.toLocaleString("hu-HU") + " Ft" : "–"}
Határidő: ${szamla.hatarido || "–"}

Ez egy automatikus emlékeztető a Családi Feladatkezelő alkalmazástól.`,
days_before: "💳 Számla emlékeztető!",
emoji: "💳",
});
setEmailKuldesAllapot(prev => ({...prev, [sid]: "sent"}));
if(auto) {
saveKoltsegData({ ...data, szamlak: szamlak.map(s=>s.id===sid?{...s,emailKikuldve:todayStr}:s) });
}
setTimeout(() => setEmailKuldesAllapot(prev => { const n={...prev}; delete n[sid]; return n; }), 4000);
} catch(e) {
setEmailKuldesAllapot(prev => ({...prev, [sid]: "error"}));
setTimeout(() => setEmailKuldesAllapot(prev => { const n={...prev}; delete n[sid]; return n; }), 4000);
}
};

