const osszkiadas = kiadasok.reduce((s,t) => s + t.osszeg, 0);
const osszbevetel = bevetelek.reduce((s,t) => s + t.osszeg, 0);
const egyenleg = osszbevetel - osszkiadas;

const katOsszeg = (katId) => kiadasok.filter(t => t.kat === katId).reduce((s,t) => s+t.osszeg, 0);
