const formatFt = (n) => n.toLocaleString("hu-HU") + " Ft";
const monthLabel = (m) => {
const [y,mo] = m.split("-");
const names = ["Jan","Feb","Már","Ápr","Máj","Jún","Júl","Aug","Sze","Okt","Nov","Dec"];
return names[parseInt(mo)-1] + " " + y;
};

