if (activeGame === "kviz") return <QuizGame user={user} onBack={goBack} />;

const todayStr = new Date().toISOString().slice(0,10);


const rs = robloxSettings || { locked: false, dailyLimit: 30, usedToday: 0, lastUsedDate: "" };
const usedTodayRoblox = rs.lastUsedDate === todayStr ? (rs.usedToday || 0) : 0;
const limitMinsRoblox = rs.dailyLimit || 30;
const remainMinsRoblox = Math.max(0, limitMinsRoblox - usedTodayRoblox);
const isLockedRoblox = rs.locked;
const isExhaustedRoblox = remainMinsRoblox <= 0;
const robloxBlocked = isLockedRoblox || isExhaustedRoblox;


const bs = backroomsSettings || { locked: false, dailyLimit: 30, usedToday: 0, lastUsedDate: "" };
