const DICT_KEY = "csaladi_szavar_v1";
function loadSuggestions() {
try { const s=localStorage.getItem(DICT_KEY); return s?JSON.parse(s):DEFAULT_TASK_SUGGESTIONS; } catch(e){ return DEFAULT_TASK_SUGGESTIONS; }
}
function saveSuggestions(data) {
localStorage.setItem(DICT_KEY, JSON.stringify(data));
}
function saveSuggestionsToSupabase(data) {

try { _supabase.from("csaladi_app").update({ suggestions: data }).eq("id","main").then(()=>{}); } catch(e) {}
}
function sortSuggestions(data) {
return data.map(g => ({ ...g, items: [...g.items].sort((a,b) => a.localeCompare(b, "hu")) }));
}

let _taskSuggestions = loadSuggestions();
function getTaskSuggestions() { return _taskSuggestions; }
function setTaskSuggestionsGlobal(data) { _taskSuggestions = data; saveSuggestions(data); }
function setTaskSuggestionsWithSupabase(data) { _taskSuggestions = data; saveSuggestions(data); saveSuggestionsToSupabase(data); }


